import {
  Column,
  Entity,
  Index,
  JoinColumn,
  ManyToOne,
  PrimaryGeneratedColumn,
} from 'typeorm';

import { Session } from '@/app/models/session';
import { Team } from '@/app/models/team';

export enum AiCoachReportStatus {
  ACCEPTED = 'accepted',
  COMPLETED = 'completed',
  FAILED = 'failed',
  CANCELLED = 'cancelled',
}

export type Params = {
  language: string;
  sessionId: string;
};

@Index('ai_coach_reports_pkey', ['id'], { unique: true })
@Index('ai_coach_reports_session_id_key', ['sessionId'])
@Index('ai_coach_reports_team_id_key', ['teamId'])
@Entity('ai_coach_reports', { schema: 'public' })
export class AiCoachReport {
  @PrimaryGeneratedColumn('uuid', { name: 'id' })
  id: string;

  @Column('uuid', { name: 'session_id', nullable: true })
  sessionId: string | null;

  @Column('uuid', { name: 'team_id' })
  teamId: string;

  @Column('jsonb', { name: 'content' })
  content: Record<string, any>; // eslint-disable-line @typescript-eslint/no-explicit-any

  @Column('jsonb', { name: 'params' })
  params: Params;

  @Column('varchar', { name: 'status' })
  status: AiCoachReportStatus;

  @Column('int', { name: 'retry_count', default: 0 })
  retryCount: number;

  @Column('timestamp with time zone', { name: 'deleted_at', nullable: true })
  deletedAt: Date | null;

  @Column('timestamp with time zone', {
    name: 'created_at',
    default: () => 'now()',
  })
  createdAt: Date;

  @Column('timestamp with time zone', {
    name: 'updated_at',
    default: () => 'now()',
  })
  updatedAt: Date;

  @ManyToOne(() => Session, { onDelete: 'SET NULL' })
  @JoinColumn([{ name: 'session_id', referencedColumnName: 'id' }])
  session: Session;

  @ManyToOne(() => Team, { onDelete: 'CASCADE' })
  @JoinColumn([{ name: 'team_id', referencedColumnName: 'id' }])
  team: Team;
}

