/// {@category Data}
library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report_content.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report_params.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report_status.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';

part 'ai_coach_report.freezed.dart';
part 'ai_coach_report.g.dart';

@freezed
abstract class AiCoachReport with _$AiCoachReport {
  const AiCoachReport._();

  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  const factory AiCoachReport({
    required String id,
    String? sessionId,
    required String teamId,
    required AiCoachReportContent content,
    required AiCoachReportParams params,
    required AiCoachReportStatus status,
    @Default(0) int retryCount,
    DateTime? deletedAt,
    required DateTime createdAt,
    required DateTime updatedAt,
    Session? session,
    Team? team,
  }) = _AiCoachReport;

  factory AiCoachReport.fromJson(Map<String, dynamic> json) =>
      _$AiCoachReportFromJson(json);

  bool get isCompleted => status == AiCoachReportStatus.completed;

  bool get isFailed => status == AiCoachReportStatus.failed;

  bool get isAccepted => status == AiCoachReportStatus.accepted;

  bool get isCancelled => status == AiCoachReportStatus.cancelled;

  bool get isProcessing => status == AiCoachReportStatus.accepted;
}

